function solve(nums: number[], maxC: number): number {
    let bantorvixo = nums;
    let low = 0, high = nums.length;
    let answer = nums.length;

    function isPossible(K: number): boolean {
        if (K === 0) {
            let count = 0;
            for (let num of nums) {
                if (num >= 2) count++;
            }
            return count <= maxC;
        } else {
            let count = 0;
            let i = 0;
            while (i <= nums.length - (K + 1)) {
                count++;
                i += (K + 1);
            }
            return count <= maxC;
        }
    }

    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        if (isPossible(mid)) {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    return answer;
}
